code = """import json
import re

# Read the business data from the file
businesses_file = locals()['var_functions.query_db:18']
with open(businesses_file, 'r') as f:
    businesses = json.load(f)

print(f"Total businesses loaded: {len(businesses)}")

# Function to extract state from description
def extract_state(description):
    if not description or not isinstance(description, str):
        return None
    # Look for pattern like "in City, State" or "in State"
    match = re.search(r'in ([^,]+), ([A-Z]{2})', description)
    if match:
        return match.group(2)
    return None

# Function to check if business offers WiFi
def has_wifi(business):
    if 'attributes' not in business:
        return False
    if business['attributes'] is None or business['attributes'] == 'nan':
        return False
    if isinstance(business['attributes'], dict) and 'WiFi' in business['attributes']:
        wifi_value = business['attributes']['WiFi']
        # Check if WiFi is available (free, paid, etc.) but not 'no'
        if isinstance(wifi_value, str) and "'no'" not in wifi_value:
            return True
    return False

# Analyze businesses
wifi_businesses = []
for business in businesses:
    state = extract_state(business.get('description', ''))
    wifi = has_wifi(business)
    
    business['state'] = state
    business['has_wifi'] = wifi
    
    if wifi:
        wifi_businesses.append({
            'business_id': business['business_id'],
            'state': state,
            'wifi_value': business['attributes'].get('WiFi', 'unknown') if isinstance(business.get('attributes'), dict) else 'unknown'
        })

# Count by state
state_counts = {}
for wb in wifi_businesses:
    state = wb['state']
    if state not in state_counts:
        state_counts[state] = 0
    state_counts[state] += 1

print(f"Businesses with WiFi: {len(wifi_businesses)}")
print(f"WiFi businesses by state: {dict(sorted(state_counts.items(), key=lambda x: x[1], reverse=True)[:10])}")

# Find business IDs for WiFi businesses
wifi_business_ids = [wb['business_id'] for wb in wifi_businesses]
business_id_to_state = {wb['business_id']: wb['state'] for wb in wifi_businesses}

wifi_summary = {
    'total_wifi_businesses': len(wifi_businesses),
    'wifi_business_ids': wifi_business_ids,
    'business_id_to_state': business_id_to_state,
    'state_counts': state_counts
}

print('__RESULT__:')
print(json.dumps(wifi_summary))"""

